<?php
 namespace League\CommonMark\Node; final class NodeWalker { private $root; private $current; private $entering; public function __construct(Node $root) { $this->root = $root; $this->current = $this->root; $this->entering = true; } public function next(): ?NodeWalkerEvent { $current = $this->current; $entering = $this->entering; if (null === $current) { return null; } if ($entering && $current->isContainer()) { if ($current->firstChild()) { $this->current = $current->firstChild(); $this->entering = true; } else { $this->entering = false; } } elseif ($current === $this->root) { $this->current = null; } elseif (null === $current->next()) { $this->current = $current->parent(); $this->entering = false; } else { $this->current = $current->next(); $this->entering = true; } return new NodeWalkerEvent($current, $entering); } public function resumeAt(Node $node, bool $entering = true) { $this->current = $node; $this->entering = $entering; } } 